    t2new += _inflate(t2new.shape, np.ix_(sO, sO, sV, sV), t2new_OOVV)
    t2new += _inflate(t2new.shape, np.ix_(sO, sO, sV, sv), t2new_OOVv)
    t2new += _inflate(t2new.shape, np.ix_(sO, sO, sv, sV), t2new_OOvV)
    t1new += _inflate(t1new.shape, np.ix_(sO, sV), t1new_OV)
    t2new += _inflate(t2new.shape, np.ix_(sO, so, sV, sV), t2new_OoVV)
    t2new += _inflate(t2new.shape, np.ix_(so, sO, sV, sV), t2new_oOVV)

    return {"t1new": t1new, "t2new": t2new, "t3new": t3new}

